  ...(Object.keys(preservedBinary).length ? { binary: preservedBinary } : {}),
}];

const item = $input.first() ?? { json: {}, binary: {} };
const json = { ...(item.json ?? {}) };

json.reviewMode = 'refine';
json.refinement = true;

const feedback = String(json.Feedback ?? json.feedback ?? '').trim();
if (feedback) {
  json.feedbackForRefinement = feedback;
  json.feedback = feedback;
}

return [{
  json,
  ...(item.binary && Object.keys(item.binary).length ? { binary: item.binary } : {}),
}];

const item = $input.first() ?? { json: {}, binary: {} };

const reviewZip = item.binary?.reviewZip;
if (!reviewZip) {
  throw new Error('Approved Requirements ZIP artifact is missing.');
}

return [{
  json: {},
  binary: {
    reviewZip,
  },
}];
